import sys, json, base64
sys.path.insert(0, ".")
calendar = json.loads(base64.b64decode("").decode())
from db.connection import get_conn
with get_conn() as conn:
    with conn.cursor() as cur:
        cur.execute(
            "INSERT INTO decisions (decided_by, decision_type, input_context, reasoning, output) "
            "VALUES (%s, %s, %s::jsonb, %s, %s::jsonb)",
            ("claude_direct", "calendar_plan",
             json.dumps({"source": "definitive_locked", "month": "2026-05"}),
             "Definitive May calendar. HM: 15/18/21/24/27/30. Audio: 16/19/22/25/28/31. Real revenue. No HM on May 14.",
             json.dumps(calendar)))
    conn.commit()
    print("Calendar inserted")
from pacing.calendar import _generate_html_report, _publish_calendar_page
from datetime import date
html = _generate_html_report(date(2026, 5, 1), calendar)
url = _publish_calendar_page(date(2026, 5, 1), html)
print("Published:", url)
